+        body: 'Your order has been shipped',
+      };
+
+      router.route(notification);
+
+      expect(emailChannel.getNotificationCount()).toBe(1);
+      expect(smsChannel.getMessageCount()).toBe(0);
+      expect(webhookChannel.getDeliveryCount()).toBe(0);
