+      const notifications = emailChannel.getNotifications();
+      expect(notifications[0]?.recipient).toBe('user@example.com');
+      expect(notifications[0]?.subject).toBe('Order Shipped');
+      expect(notifications[0]?.body).toBe('Your order has been shipped');
