+        priority: 'low',
+        recipient: 'system-monitor',
+        subject: 'Info',
+        body: 'Minor update',
+      };
+
+      router.route(notification);
+
+      const deliveries = webhookChannel.getDeliveries();
+      expect(deliveries[0]?.url).toBe('https://hooks.default/notifications');
+    });
