+    it('should route multiple notifications to correct channels', () => {
+      router.route({
+        priority: 'urgent',
+        recipient: '+1111111111',
+        subject: 'Alert',
+        body: 'Urgent alert',
+      });
+      router.route({
+        priority: 'normal',
+        recipient: 'user@example.com',
+        subject: 'Update',
+        body: 'Normal update',
+      });
+      router.route({
+        priority: 'low',
+        recipient: 'logger',
+        subject: 'Log',
+        body: 'Low priority log',
+        webhookUrl: 'https://hooks.example.com/log',
+      });
+
+      expect(smsChannel.getMessageCount()).toBe(1);
+      expect(emailChannel.getNotificationCount()).toBe(1);
+      expect(webhookChannel.getDeliveryCount()).toBe(1);
